const body = $json.body || $json;
const caller = body.caller || body.from || body.phone || '';
const business = body.businessName || '[Business Name]';
const event = {
  receivedAt: new Date().toISOString(),
  caller,
  businessName: business,
  source: body.source || 'missed_call_webhook',
  callStatus: body.callStatus || 'missed',
  ownerChannel: body.ownerChannel || 'owner_alert',
  status: 'Needs callback',
  nextAction: 'Reply or call back within 5 minutes'
};
event.textBackMessage = `Sorry we missed your call. This is ${business}. Reply here with what you need help with and the best time to call you back. Reply STOP to opt out.`;
event.ownerAlert = `Missed call from ${caller || 'unknown caller'}. Text-back prepared. Next action: ${event.nextAction}.`;
return [{ json: event }];
